import React, { useState, useEffect, useContext } from "react";
import { Card, CardContent } from "../components/ui/card";
import { Button } from "../components/ui/Button";
import { Input } from "../components/ui/input";
import logo from "../logo.png";
import {
  MapPin,
  Search as SearchIcon,
  Heart,
  Globe,
  Menu as MenuIcon,
  PlusCircle,
} from "lucide-react";
import { Link } from "react-router-dom";
import { AuthContext } from "../context/AuthContext";
import apiRequest from "../services/api";
import LoginModal from "../components/LoginModal";
import RegisterModal from "../components/RegisterModal";
import CreateListingModal from "../components/CreateListingModal";

const PRIMARY_GREEN = "#012F01";
const ACCENT_GREEN = "#025220";
const SOFT_GREEN = "#E5F2E8";

const categories = [
  { name: "Al-Malki", emoji: "🏙️" },
  { name: "Mazzeh", emoji: "🌇" },
  { name: "Mezzeh Villas", emoji: "🏡" },
  { name: "Abu Rummaneh", emoji: "🌿" },
  { name: "Shaalan", emoji: "🛍️" },
  { name: "Bab Touma", emoji: "🏛️" },
  { name: "Al-Qasaa", emoji: "🌳" },
  { name: "Al-Hamidiyah", emoji: "🕌" },
  { name: "Old City", emoji: "🏚️" },
];

export default function HomePage() {
  const [query, setQuery] = useState("");
  const [listings, setListings] = useState([]);
  const [loading, setLoading] = useState(true);

  const { user, logout, loading: authLoading } = useContext(AuthContext);
  const [isLoginModalOpen, setLoginModalOpen] = useState(false);
  const [isRegisterModalOpen, setRegisterModalOpen] = useState(false);
  const [isCreateListingModalOpen, setCreateListingModalOpen] = useState(false);

  useEffect(() => {
    const fetchListings = async () => {
      setLoading(true);
      try {
        const data = await apiRequest(`/api/properties?search=${query}`);
        setListings(data.properties || []);
      } catch (err) {
        console.error("Failed to load listings", err);
      } finally {
        setLoading(false);
      }
    };
    fetchListings();
  }, [query]);

  const handleListingCreated = (newListing) => {
    setListings((prev) => [newListing, ...prev]);
  };

  const filtered = listings;

  return (
    <div className="min-h-screen text-gray-900" style={{ backgroundColor: SOFT_GREEN }}>
      {/* Navigation */}
      <nav className="bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto flex items-center justify-between px-6 py-4">
          <div className="flex items-center gap-2">
            <img src={logo} alt="Nawartu Logo" className="h-11 w-11" />
            <span className="text-2xl font-extrabold" style={{ color: PRIMARY_GREEN }}>
              Nawartu
            </span>
          </div>
          <div className="flex items-center gap-4">
            {!authLoading && (
              <>
                {user ? (
                  <>
                    <Button onClick={() => setCreateListingModalOpen(true)} className="hidden sm:inline-flex items-center gap-2">
                      <PlusCircle size={16} /> List your place
                    </Button>
                    <Button onClick={logout} variant="outline">Logout</Button>
                  </>
                ) : (
                  <>
                    <Button onClick={() => setLoginModalOpen(true)}>Log In</Button>
                    <Button onClick={() => setRegisterModalOpen(true)} variant="outline">Sign Up</Button>
                  </>
                )}
              </>
            )}
            <button className="p-2 rounded-full hover:bg-gray-100">
              <Globe className="w-5 h-5" />
            </button>
            <button className="p-2 rounded-full border hover:shadow-sm">
              <MenuIcon className="w-5 h-5" />
            </button>
          </div>
        </div>
      </nav>

      {/* Search bar */}
      <section className="flex justify-center py-6" style={{ backgroundColor: PRIMARY_GREEN }}>
        <div className="w-full max-w-3xl flex items-center bg-white rounded-full shadow-lg px-6 py-4 gap-3">
          <SearchIcon className="w-5 h-5 text-gray-500" />
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search destinations, homes, experiences..."
            className="flex-1 outline-none text-sm"
          />
          <button className="w-12 h-12 flex items-center justify-center rounded-full text-white" style={{ backgroundColor: ACCENT_GREEN }}>
            <SearchIcon className="w-5 h-5" />
          </button>
        </div>
      </section>

      {/* Category row */}
      <div className="py-6 bg-white shadow-sm">
        <div className="flex flex-wrap justify-center gap-6 max-w-6xl mx-auto">
          {categories.map((c) => (
            <button
              key={c.name}
              className="flex flex-col items-center gap-1 text-sm text-gray-700 hover:text-[var(--accent)] transition"
              style={{ '--accent': ACCENT_GREEN }}>
              <span className="text-xl">{c.emoji}</span>
              {c.name}
            </button>
          ))}
        </div>
      </div>

      {/* Listings */}
      <main className="max-w-6xl mx-auto p-6 grid gap-8 sm:grid-cols-2 lg:grid-cols-3">
        {loading ? (
          <p>Loading listings...</p>
        ) : filtered.length === 0 ? (
          <p>No listings found.</p>
        ) : (
          filtered.map((home) => (
            <Card key={home._id} className="overflow-hidden hover:shadow-xl transition-shadow duration-300 bg-white rounded-xl">
              <Link to={`/property/${home._id}`} className="block">
                <div className="relative group">
                  <img
                    src={home.images?.[0] || "https://picsum.photos/800/600"}
                    alt={home.title}
                    className="h-56 w-full object-cover group-hover:scale-105 transition-transform duration-300"
                  />
                  <button
                    className="absolute top-3 right-3 bg-white/80 rounded-full p-1 hover:bg-[var(--accent)]"
                    style={{ '--accent': ACCENT_GREEN }}>
                    <Heart className="w-4 h-4 text-[var(--accent)]" />
                  </button>
                </div>
              </Link>
              <CardContent>
                <div className="flex items-center gap-1 text-sm text-gray-500 mb-1">
                  <MapPin className="w-4 h-4" /> {home.location?.neighborhood || 'Damascus'}
                </div>
                <h2 className="font-semibold text-lg leading-tight mb-1">{home.title}</h2>
                <p className="text-sm text-gray-500 mb-2">
                  {home.capacity?.guests || 2} guests · {home.capacity?.bedrooms || 1} bedroom
                </p>
                <p>
                  <span className="font-bold text-[var(--accent)]" style={{ '--accent': PRIMARY_GREEN }}>
                    ${home.price}
                  </span>
                  <span className="text-gray-500"> / night</span>
                </p>
              </CardContent>
            </Card>
          ))
        )}
      </main>

      {/* Modals */}
      <LoginModal
        isOpen={isLoginModalOpen}
        onClose={() => setLoginModalOpen(false)}
        onSwitchToRegister={() => {
          setLoginModalOpen(false);
          setRegisterModalOpen(true);
        }}
      />
      <RegisterModal
        isOpen={isRegisterModalOpen}
        onClose={() => setRegisterModalOpen(false)}
        onSwitchToLogin={() => {
          setRegisterModalOpen(false);
          setLoginModalOpen(true);
        }}
      />
      {user && (
        <CreateListingModal
          isOpen={isCreateListingModalOpen}
          onClose={() => setCreateListingModalOpen(false)}
          onListingCreated={handleListingCreated}
        />
      )}
    </div>
  );
}
